import { useEffect, useState } from 'react';
import { propertyAPI } from '../services/api';
import API from '../services/api';

export default function AdminPanel() {
    const [pendingProperties, setPendingProperties] = useState([]);

    useEffect(() => {
        loadPendingProperties();
    }, []);

    const loadPendingProperties = async () => {
        // You need to add this endpoint in PropertyController
        const res = await API.get('/properties/pending');
        setPendingProperties(res.data);
    };

    const approveProperty = async (propertyId) => {
        await propertyAPI.approve(propertyId);
        alert("Property approved!");
        loadPendingProperties();
    };

    return (
        <div>
            <h1>👑 Admin Dashboard</h1>
            <h2>Pending Approvals</h2>
            {pendingProperties.map(property => (
                <div key={property.id}>
                    <h3>{property.title}</h3>
                    <p>Owner: {property.owner?.email}</p>
                    <p>Location: {property.location}</p>
                    <button onClick={() => approveProperty(property.id)}>✅ Approve</button>
                </div>
            ))}
        </div>
    );
}
